mapper.select:
SELECT r.* FROM nursing_exam_record r LEFT JOIN sys_user u ON r.user_id = u.user_id AND u.is_delete = 0 LEFT JOIN nursing_exam e ON r.exam_id = e.exam_id AND e.is_delete = 0 WHERE 1 = 1
AND r.exam_id = #{dto.examId}
AND r.user_id = #{dto.userId}
AND (u.real_name LIKE CONCAT('%', #{dto.username}, '%') OR u.username LIKE CONCAT('%', #{dto.username}, '%'))
AND r.is_pass = #{dto.isPass}
ORDER BY r.create_time DESC
